 3	import { tickLabels } from '@kubevirt-utils/components/Charts/ChartLabels/styleOverrides';
 4	import useResponsiveCharts from '@kubevirt-utils/components/Charts/hooks/useResponsiveCharts';
 5	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 6	import { ChartAxis, ChartContainer } from '@patternfly/react-charts';
 7	
 8	import { formatTimestamp, getTimeTickValues } from '../utils';
 9	
10	type MigrationsTimeAxisProps = {
11	  domainX: [number, number];
12	  timespan: number;
13	};
14	
15	const MigrationsTimeAxis: FC<MigrationsTimeAxisProps> = ({ domainX, timespan }) => {
16	  const { t } = useKubevirtTranslation();
17	  const { width } = useResponsiveCharts();
18	  return (
19	    <div className="co-utilization-card__item co-utilization-card__item-header">
20	      <div className="co-utilization-card__item-section co-u-hidden co-u-visible-on-xl">
