22	          {t('Resource')}
23	        </span>
24	      </div>
25	      <div className="co-utilization-card__item-chart co-utilization-card__item-chart--times">
26	        <ChartAxis
27	          axisComponent={<></>}
28	          containerComponent={<ChartContainer title={t('Time axis')} />}
29	          domain={{ x: domainX }}
30	          fixLabelOverlap
31	          height={15}
32	          orientation="top"
33	          padding={{ bottom: 0, left: 70, right: 0, top: 30 }}
34	          scale={{ x: 'time' }}
35	          style={{ tickLabels }}
36	          tickFormat={(time) => formatTimestamp(timespan, time, true)}
37	          tickValues={getTimeTickValues(domainX)}
38	          width={width}
39	        />
40	      </div>
41	    </div>
42	  );
43	};
44	
45	export default MigrationsTimeAxis;

